  "code": "import {AbsoluteFill, useCurrentFrame, useVideoConfig} from 'remotion';

const PARAMS = {
  primaryColor: '#FFA500',    // type: color
  secondaryColor: '#FF4500',  // type: color
  speed: 1.0,                  // type: range, min: 0.1, max: 3.0
  text: 'Brand Race',           // type: text
  fontSize: 80,                // type: range, min: 20, max: 200, unit: px
  visible: true,               // type: boolean
  animStyle: 'linear',         // type: select, options: bounce|spring|linear
} as const;

const brands = [
  {name: 'Apple', value: 320},
  {name: 'Samsung', value: 280},
  {name: 'Xiaomi', value: 200},
  {name: 'Google', value: 150},
  {name: 'Sony', value: 100}
];

export const GeneratedAsset = ({
  primaryColor = PARAMS.primaryColor,
  speed = PARAMS.speed,
  text = PARAMS.text,
  fontSize = PARAMS.fontSize,
  visible = PARAMS.visible,
}: typeof PARAMS = PARAMS) => {
