      <div style={{width: '100%', height: '100%', position: 'relative'}}> 
        {brands.map((brand, index) => {
          const progress = interpolate(
            frame,
            [0, durationInFrames],
            [0, brand.value],
            {extrapolateRight: 'clamp'}
          );
          return (
            <div key={brand.name} style={{margin: '10px 0', position: 'relative'}}>
