import { useCurrentFrame, useVideoConfig, AbsoluteFill, interpolate } from 'remotion';

const PARAMS = {
  duration: 24, // type: range, min: 1, max: 90
} as const;

export const GeneratedAsset = ({ duration = PARAMS.duration }: typeof PARAMS = PARAMS) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();
  const progress = frame / (duration * fps);

  const rgbOffset = interpolate(progress, [0, 0.3, 0.4, 1], [0, 10, -10, 0]);

  return (
    <AbsoluteFill style={{ backgroundColor: 'black' }}>
      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'transparent', clipPath: `inset(0 0 0 ${rgbOffset}px)` }}>
        {/* Scene 1 Content */}
      </div>
      <div style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'transparent', filter: `translateX(${rgbOffset}px)` }}>
        {/* Scene 2 Content */}
      </div>
    </AbsoluteFill>
  );
};

