{
  "mode": "generate",
  "title": "Sequential Timeline with Dots and Lines",
  "code": "const PARAMS = {
  primaryColor: "#7C3AED",     // type: color
  secondaryColor: "#A78BFA",   // type: color
  speed: 1.0,                  // type: range, min: 0.1, max: 3.0
  text: "Timeline",            // type: text
  fontSize: 80,                // type: range, min: 20, max: 200, unit: px
  visible: true,               // type: boolean
  animStyle: "bounce",         // type: select, options: bounce|spring|linear
} as const;

export const GeneratedAsset = ({
  primaryColor = PARAMS.primaryColor,
  secondaryColor = PARAMS.secondaryColor,
  speed = PARAMS.speed,
  text = PARAMS.text,
  fontSize = PARAMS.fontSize,
  visible = PARAMS.visible,
  animStyle = PARAMS.animStyle,
}: typeof PARAMS = PARAMS) => {
  const frame = useCurrentFrame();
  const { durationInFrames } = useVideoConfig();
  const totalDots = 4;
  const revealDuration = Math.floor(durationInFrames / totalDots);

  return (
    <AbsoluteFill style={{ backgroundColor: 'transparent' }}>
      <svg width="100%" height="100%">
        {/* Draw the timeline line */}
        <line x1="10%" y1="50%" x2="90%" y2="50%" stroke={secondaryColor} strokeWidth="2" />
        {/* Create dots for each year */}
        {[2020, 2021, 2022, 2023].map((year, index) => {
          const position = 10 + index * 20; // calculate position
          const isVisible = frame > index * revealDuration;
          return (
            <circle
              key={year}
              cx={`${position}%`}
              cy="50%"
              r="8"
              fill={isVisible ? primaryColor : 'transparent'}
              stroke={isVisible ? primaryColor : 'transparent'}
              strokeWidth="2"
            />
          );
        })}
        {/* Display text for each year */}
        {[2020, 2021, 2022, 2023].map((year, index) => {
          const position = 10 + index * 20;
          return (
            <text
              key={`text-${year}`}
              x={`${position}%`}
              y="55%"
              fontSize={fontSize}
              fill={primaryColor}
              opacity={frame > index * revealDuration ? 1 : 0}
              style={{transition: \`opacity ${speed}s\`,}}
            >
              {year}
            </text>
          );
        })}
      </svg>
    </AbsoluteFill>
  );
};",
  "durationInFrames": 150,
  "fps": 30,
  "width": 1920,
  "height": 1080
}
